# 创建字典
student = {
    'name': '小明',
    'age': 20,
    'score': 95
}
print(student)  # {'name': '小明', 'age': 20, 'score': 95}

# 空字典
empty = {}

# 添加和修改
student = {'name': '小明'}

# 添加
student['age'] = 20
print(student)  # {'name': '小明', 'age': 20}

# 修改
student['age'] = 21
print(student)  # {'name': '小明', 'age': 21}

# 删除键值对
student = {'name': '小明', 'age': 20, 'score': 95}

# del 删除
del student['score']
print(student)  # {'name': '小明', 'age': 20}

# pop 删除并返回
age = student.pop('age')
print(age)      # 20
print(student)  # {'name': '小明'}

# 遍历字典
student = {'name': '小明', 'age': 20, 'score': 95}

# 遍历键
for key in student.keys():
    print(key)

# 遍历值
for value in student.values():
    print(value)

# 遍历键值对
for key, value in student.items():
    print(f'{key}: {value}')

